622	export const createClarificationQuestions = async (
623	  projectPath: string,
624	  ticketId: string,
625	  inputs: ClarificationQuestionCreateInput[],
626	  options: {
627	    actor: RelayActor;
628	    source: RelayEventSource;
629	    runId?: string | null;
630	    codexThreadId?: string | null;
631	  }
632	): Promise<ClarificationQuestion[]> => {
633	  await readTicket(projectPath, ticketId);
634	  const existing = await readClarificationQuestions(projectPath, ticketId);
635	  const now = nowIso();
636	  const created = inputs
637	    .map((input) => ({
638	      question: input.question.trim(),
639	      answerType: input.answerType ?? "text"
640	    }))
641	    .filter((input) => input.question.length > 0)
642	    .map((input): ClarificationQuestion => ({
643	      id: newId("clar"),
644	      ticketId,
645	      question: input.question,
646	      answerType: input.answerType,
647	      answer: null,
648	      createdAt: now,
649	      updatedAt: now,
650	      answeredAt: null,
651	      createdBy: options.actor,
652	      source: options.source,
653	      runId: options.runId ?? null,
654	      codexThreadId: options.codexThreadId ?? null
655	    }));
656	
657	  if (created.length === 0) return [];
658	
659	  await writeClarificationQuestions(projectPath, ticketId, [...existing, ...created]);
660	  for (const question of created) {
661	    await appendAuditEvent(projectPath, {
662	      actor: options.actor,
663	      source: options.source,
664	      eventType: "clarification.question_created",
665	      ticketId,
666	      runId: options.runId ?? null,
667	      payload: {
668	        questionId: question.id,
669	        question: question.question,
670	        answerType: question.answerType
671	      }
672	    });
673	  }
674	  return created;
675	};
