677	export const answerClarificationQuestion = async (
678	  projectPath: string,
679	  ticketId: string,
680	  questionId: string,
681	  answer: string
682	): Promise<ClarificationQuestion> => {
683	  const trimmed = answer.trim();
684	  if (!trimmed) throw new Error("Clarification answer cannot be empty.");
685	
686	  const questions = await readClarificationQuestions(projectPath, ticketId);
687	  const target = questions.find((question) => question.id === questionId);
688	  if (!target) throw new Error(`Unknown clarification question: ${questionId}`);
689	
690	  const now = nowIso();
691	  const updated: ClarificationQuestion = {
692	    ...target,
693	    answer: trimmed,
694	    answeredAt: now,
695	    updatedAt: now
696	  };
697	  const nextQuestions = questions.map((question) => (question.id === questionId ? updated : question));
698	  await writeClarificationQuestions(projectPath, ticketId, nextQuestions);
699	  await appendAuditEvent(projectPath, {
700	    actor: "user",
701	    source: "clarification_ui",
702	    eventType: "clarification.answer_submitted",
703	    ticketId,
704	    runId: target.runId,
705	    payload: {
706	      questionId,
707	      answer: trimmed
708	    }
709	  });
710	  return updated;
711	};
