 32	const useProgressNow = (active: boolean, now?: number): number => {
 33	  const [currentNow, setCurrentNow] = useState(() => now ?? Date.now());
 34	
 35	  useEffect(() => {
 36	    if (now !== undefined) {
 37	      setCurrentNow(now);
 38	      return undefined;
 39	    }
 40	    if (!active) {
 41	      setCurrentNow(Date.now());
 42	      return undefined;
 43	    }
 44	    const interval = window.setInterval(() => setCurrentNow(Date.now()), 1000);
 45	    return () => window.clearInterval(interval);
 46	  }, [active, now]);
 47	
 48	  return now ?? currentNow;
 49	};
