 40	export const isAgentSessionActive = (status: AgentProgressStatus): boolean => status === "running" || status === "drafting";
 41	
 42	export const formatElapsedDuration = (durationMs: number | null): string => {
 43	  if (durationMs === null) return "Unavailable";
 44	  const totalSeconds = Math.max(0, Math.floor(durationMs / 1000));
 45	  const seconds = totalSeconds % 60;
 46	  const totalMinutes = Math.floor(totalSeconds / 60);
 47	  const minutes = totalMinutes % 60;
 48	  const hours = Math.floor(totalMinutes / 60);
 49	  return hours > 0 ? `${hours}:${pad2(minutes)}:${pad2(seconds)}` : `${pad2(minutes)}:${pad2(seconds)}`;
 50	};
 51	
 52	export const isWebSearchEvent = (event: RendererRunEvent): boolean =>
 53	  event.type === "web.search" || (event.type === "agent.message.delta" && /^web search:/i.test(event.text.trim()));
 54	
 55	export const agentEventText = (event: RendererRunEvent): string => {
 56	  switch (event.type) {
 57	    case "run.started":
 58	      return `Run started (${event.threadId})`;
 59	    case "agent.message.delta":
 60	    case "agent.message.completed":
 61	      return event.text;
 62	    case "command.started":
 63	      return `$ ${event.command}`;
 64	    case "command.output":
 65	      return event.text;
 66	    case "command.completed":
 67	      return `Command ${event.status}`;
 68	    case "file.change":
 69	      return event.summary ?? event.path;
 70	    case "web.search":
 71	      return `Web search: ${event.query}`;
 72	    case "approval.requested":
 73	      return `Approval requested: ${event.kind}`;
 74	    case "approval.resolved":
 75	      return `Approval ${event.decision}`;
 76	    case "ticket.status_changed":
 77	      return `Status moved from ${event.fromStatus} to ${event.toStatus}`;
 78	    case "clarification.requested":
 79	      return `${event.questions.length} clarification question${event.questions.length === 1 ? "" : "s"} requested`;
 80	    case "run.completed":
 81	      return event.finalResponse;
 82	    case "run.failed":
 83	      return event.message;
 84	    default:
 85	      return "";
 86	  }
 87	};
