 92	export const agentEventLabel = (event: RendererRunEvent): string => {
 93	  switch (event.type) {
 94	    case "run.started":
 95	    case "run.completed":
 96	    case "run.failed":
 97	      return "Run";
 98	    case "agent.message.delta":
