100	      return isWebSearchEvent(event) ? "Web Search" : "Message";
101	    case "command.started":
102	    case "command.output":
103	    case "command.completed":
104	      return "Command";
105	    case "file.change":
106	      return "File";
107	    case "web.search":
108	      return "Web Search";
109	    case "approval.requested":
110	    case "approval.resolved":
111	      return "Approval";
112	    case "ticket.status_changed":
113	      return "Status";
114	    case "clarification.requested":
115	      return "Clarification";
