121	export const agentEventTone = (event: RendererRunEvent): "neutral" | "success" | "warning" | "danger" | "info" => {
122	  if (event.type === "run.failed" || (event.type === "command.completed" && event.status === "failed")) return "danger";
123	  if (event.type === "run.completed" || (event.type === "command.completed" && event.status === "completed")) return "success";
124	  if (event.type === "clarification.requested" || event.type === "approval.requested") return "warning";
125	  if (isWebSearchEvent(event) || event.type === "file.change" || event.type === "ticket.status_changed") return "info";
126	  return "neutral";
127	};
