129	export const sortAgentEvents = (events: RendererRunEvent[]): RendererRunEvent[] =>
130	  events
131	    .map((event, index) => ({ event, index }))
132	    .sort((a, b) => eventTime(a.event) - eventTime(b.event) || a.index - b.index)
133	    .map(({ event }) => event);
134	
135	export const mergeRunEvents = (...eventGroups: RendererRunEvent[][]): RendererRunEvent[] => {
136	  const merged = new Map<string, RendererRunEvent>();
137	  for (const event of eventGroups.flat()) {
138	    const key = `${event.runId}|${event.timestamp}|${event.type}|${agentEventText(event)}`;
139	    if (!merged.has(key)) merged.set(key, event);
140	  }
141	  return sortAgentEvents([...merged.values()]);
142	};
