144	const statusCopy = (
145	  status: AgentProgressStatus
146	): Pick<AgentProgressMetrics, "statusLabel" | "statusDetail" | "statusTone"> => {
147	  switch (status) {
148	    case "drafting":
149	      return { statusLabel: "Drafting", statusDetail: "Codex is preparing a ticket draft.", statusTone: "active" };
150	    case "running":
151	      return { statusLabel: "Active", statusDetail: "Codex is working on this ticket.", statusTone: "active" };
152	    case "blocked":
153	      return { statusLabel: "Needs input", statusDetail: "Codex is waiting on clarification.", statusTone: "warning" };
154	    case "failed":
155	      return { statusLabel: "Failed", statusDetail: "The agent session ended with an error.", statusTone: "danger" };
156	    case "completed":
157	      return { statusLabel: "Completed", statusDetail: "The latest agent session has finished.", statusTone: "success" };
158	    case "cancelled":
159	      return { statusLabel: "Cancelled", statusDetail: "The latest agent session was stopped.", statusTone: "danger" };
160	    case "idle":
161	    default:
162	      return { statusLabel: "Inactive", statusDetail: "No agent session is currently active.", statusTone: "idle" };
163	  }
164	};
