166	export const deriveAgentProgress = ({
167	  events,
168	  status,
169	  startedAt,
170	  endedAt,
171	  now = Date.now(),
172	  metricsAvailable
173	}: AgentProgressInput): AgentProgressMetrics => {
174	  const sorted = sortAgentEvents(events);
175	  const active = isAgentSessionActive(status);
176	  const firstEvent = sorted[0] ?? null;
177	  const lastEvent = sorted.at(-1) ?? null;
178	  const runStarted = sorted.find((event) => event.type === "run.started") ?? null;
179	  const terminalEvent =
180	    [...sorted].reverse().find((event) => event.type === "run.completed" || event.type === "run.failed" || event.type === "clarification.requested") ??
181	    null;
182	
183	  const effectiveStartedAt = startedAt ?? runStarted?.timestamp ?? firstEvent?.timestamp ?? null;
184	  const effectiveEndedAt = endedAt ?? (active ? null : terminalEvent?.timestamp ?? lastEvent?.timestamp ?? null);
185	  const startMs = timestampMs(effectiveStartedAt);
186	  const endMs = active ? now : timestampMs(effectiveEndedAt);
187	  const elapsedMs = startMs !== null && endMs !== null ? Math.max(0, endMs - startMs) : null;
188	  const haveMetrics = metricsAvailable ?? sorted.length > 0;
189	  const filesEdited = haveMetrics ? new Set(sorted.filter((event) => event.type === "file.change").map((event) => event.path)).size : null;
190	  const webSearches = haveMetrics ? sorted.filter(isWebSearchEvent).length : null;
191	
192	  return {
193	    ...statusCopy(status),
194	    active,
195	    elapsedMs,
196	    elapsedLabel: formatElapsedDuration(elapsedMs),
197	    filesEdited,
198	    webSearches,
199	    totalEvents: sorted.length,
200	    startedAt: effectiveStartedAt,
201	    endedAt: effectiveEndedAt,
202	    lastEventAt: lastEvent?.timestamp ?? null,
203	    metricsAvailable: haveMetrics
204	  };
205	};

